import { NextRequest, NextResponse } from 'next/server';
import { verifyPassword } from '@/server/lib/auth/password';
import { createToken } from '@/server/lib/auth/jwt';
import type { LoginRequest, LoginResponse } from '@/types/admin';

/**
 * ログインAPI
 * POST /api/admin/auth
 */
export async function POST(request: NextRequest): Promise<NextResponse<LoginResponse>> {
  try {
    const body = (await request.json()) as LoginRequest;
    const { password } = body;

    if (!password) {
      return NextResponse.json(
        { success: false, error: 'パスワードを入力してください' },
        { status: 400 }
      );
    }

    // パスワード検証
    const isValid = verifyPassword(password);

    if (!isValid) {
      return NextResponse.json(
        { success: false, error: 'パスワードが正しくありません。再度お試しください。' },
        { status: 401 }
      );
    }

    // JWT トークン生成
    const token = await createToken();

    // HttpOnly Cookie に JWT をセット
    const response = NextResponse.json({ success: true });
    response.cookies.set('admin_token', token, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      maxAge: parseInt(process.env.JWT_EXPIRES_IN || '3600', 10),
      path: '/',
    });

    return response;
  } catch (error) {
    console.error('Login error:', error);
    return NextResponse.json(
      {
        success: false,
        error: 'ログイン処理中にエラーが発生しました。しばらくしてからお試しください。',
      },
      { status: 500 }
    );
  }
}

